solution: ```class Trie {
    struct Node {
        Node* children[26] = {};
        bool isEnd = false;
    };
    Node* root;
public:
    Trie() {
        root = new Node();
    }

    void insert(string word) {
        Node* cur = root;
        for (char c : word) {
            int idx = c - 'a';
            if (!cur->children[idx]) cur->children[idx] = new Node();
            cur = cur->children[idx];
        }
        cur->isEnd = true;
    }

    bool search(string word) {
        Node* cur = root;
        for (char c : word) {
            int idx = c - 'a';
            if (!cur->children[idx]) return false;
            cur = cur->children[idx];
        }
        return cur->isEnd;
    }

    bool startsWith(string prefix) {
        Node* cur = root;
        for (char c : prefix) {
            int idx = c - 'a';
            if (!cur->children[idx]) return false;
            cur = cur->children[idx];
        }
        return true;
    }
};
```
efficiency: HIGH
time complexity: O(L) per operation, where L is the length of the word/prefix
space complexity: O(N*M) where N is the number of inserted words and M is the average length
energy implications: LOW
explanation: Uses a fixed-size array of 26 pointers per node for O(1) child access, avoiding hash overhead. Each operation walks the trie once, giving optimal linear time. Memory is proportional to total characters stored; no dynamic resizing or extra indirection.

